Validating and handling data entered into input fields is crucial to ensure that the data is accurate, secure, and properly formatted before it is saved. Here’s a step-by-step approach to validating and handling form data:

### 1. Client-Side Validation
Client-side validation is performed in the browser and provides immediate feedback to the user, enhancing the user experience.

#### JavaScript Example:
```javascript
function validateForm() {
    const name = document.getElementById('name').value;
    const email = document.getElementById('email').value;
    const phone = document.getElementById('phone').value;

    // Validate Name
    if (!name || name.trim() === '') {
        alert("Name is required.");
        return false;
    }

    // Validate Email
    const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailPattern.test(email)) {
        alert("Please enter a valid email address.");
        return false;
    }

    // Validate Phone Number
    const phonePattern = /^\d{10}$/; // Assuming a 10-digit phone number
    if (!phonePattern.test(phone)) {
        alert("Please enter a valid 10-digit phone number.");
        return false;
    }

    // If all validations pass, proceed to save the data
    return true;
}
```

### 2. Server-Side Validation
Server-side validation ensures that the data is validated even if the client-side validation fails. This is critical for security and data integrity.

#### Example Using Node.js and Express:
```javascript
const express = require('express');
const bodyParser = require('body-parser');
const app = express();

app.use(bodyParser.urlencoded({ extended: true }));

app.post('/submit-form', (req, res) => {
    const { name, email, phone } = req.body;

    // Validate Name
    if (!name || name.trim() === '') {
        return res.status(400).send({ error: "Name is required." });
    }

    // Validate Email
    const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailPattern.test(email)) {
        return res.status(400).send({ error: "Please enter a valid email address." });
    }

    // Validate Phone Number
    const phonePattern = /^\d{10}$/; // Assuming a 10-digit phone number
    if (!phonePattern.test(phone)) {
        return res.status(400).send({ error: "Please enter a valid 10-digit phone number." });
    }

    // Save the data to the database or perform other actions
    // For example, saving to a database
    // db.saveData(name, email, phone);

    res.send({ success: "Data saved successfully." });
});

app.listen(3000, () => {
    console.log('Server running on port 3000');
});
```

### 3. Data Sanitization
Sanitize the data to prevent SQL injection, XSS attacks, and other security vulnerabilities.

#### Example Using Node.js and Express:
```javascript
const escapeHtml = (html) => {
    return html.replace(/&/g, "&amp;")
               .replace(/</g, "&lt;")
               .replace(/>/g, "&gt;")
               .replace(/"/g, "&quot;")
               .replace(/'/g, "&#039;");
};

app.post('/submit-form', (req, res) => {
    const { name, email, phone } = req.body;

    // Sanitize the data
    name = escapeHtml(name);
    email = escapeHtml(email);
    phone = escapeHtml(phone);

    // Validate Name
    if (!name || name.trim() === '') {
        return res.status(400).send({ error: "Name is required." });
    }

    // Validate Email
    const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailPattern.test(email)) {
        return res.status(400).send({ error: "Please enter a valid email address." });
    }

    // Validate Phone Number
    const phonePattern = /^\d{10}$/; // Assuming a 10-digit phone number
    if (!phonePattern.test(phone)) {
        return res.status(400).send({ error: "Please enter a valid 10-digit phone number." });
    }

    // Save the sanitized data to the database or perform other actions
    // For example, saving to a database
    // db.saveData(name, email, phone);

    res.send({ success: "Data saved successfully." });
});
```

### 4. Saving Data to a Database
Once the data passes all validations, it can be saved to a database.

#### Example Using Node.js and MongoDB:
```javascript
const mongoose = require('mongoose');

// Define a schema
const userSchema = new mongoose.Schema({
    name: String,
    email: String,
    phone: String
});

const User = mongoose.model('User', userSchema);

app.post('/submit-form', async (req, res) => {
    const { name, email, phone } = req.body;

    // Validate Name
    if (!name || name.trim() === '') {
        return res.status(400).send({ error: "Name is required." });
    }

    // Validate Email
    const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailPattern.test(email)) {
        return res.status(400).send({ error: "Please enter a valid email address." });
    }

    // Validate Phone Number
    const phonePattern = /^\d{10}$/; // Assuming a 10-digit phone number
    if (!phonePattern.test(phone)) {
        return res.status(400).send({ error: "Please enter a valid 10-digit phone number." });
    }

    // Sanitize the data
    name = escapeHtml(name);
    email = escapeHtml(email);
    phone = escapeHtml(phone);

    try {
        const newUser = new User({ name, email, phone });
        await newUser.save();
        res.send({ success: "Data saved successfully." });
    } catch (error) {
        res.status(500).send({ error: "Failed to save data." });
    }
});
```

### Summary
- **Client-Side Validation**: Provides immediate feedback to the user and enhances the user experience.
- **Server-Side Validation**: Ensures data integrity and prevents security vulnerabilities.
- **Data Sanitization**: Protects against SQL injection, XSS, and other attacks.
- **Saving Data**: Stores the validated and sanitized data in a database.

By following these steps, you can ensure that the data entered into a web form is accurate, secure, and properly handled.
